import 'dart:io'; void main() { final dir = Directory('lib'); var regex = RegExp(r'const\s+(Icon|TextStyle|BoxDecoration|BorderSide|LinearGradient|Divider|Text|CircleAvatar|Row|Column|Padding|AlwaysStoppedAnimation|InputDecoration|Color|FractionallySizedBox|Container|_GoalColors|Border|EdgeInsets)\b'); var regexList = RegExp(r'const\s+\['); for (var file in dir.listSync(recursive: true)) { if (file is File && file.path.endsWith('.dart')) { var content = file.readAsStringSync(); content = content.replaceAll(regex, r'$1'); content = content.replaceAll(regexList, r'['); file.writeAsStringSync(content); } } }
